def largest_prime_factor(n: int):
    largest_factor = 1
    while n % 2 == 0:
        largest_factor = 2
        n = n // 2
    i = 3
    while i * i <= n:
        while n % i == 0:
            largest_factor = i
            n = n // i
        i += 2
    if n > 2:
        largest_factor = n
    return largest_factor
